// Extraer datos de la llamada entrante
const body = $input.first().json.body || $input.first().json;

const numero = body.numero || body.phone_number || 'desconocido';
const nombre = body.nombre || body.caller_name || 'Número desconocido';

// Mapear número a ID de contacto (debe coincidir con contactos.js)
const mapaContactos = {
  '+56912345678': { id: 'mama',       nombre: 'Mamá' },
  '+56987654321': { id: 'papa',       nombre: 'Papá' },
  '+56911222333': { id: 'hijo',       nombre: 'Carlos' },
  '+56944555666': { id: 'hija',       nombre: 'María' },
  '+56977888999': { id: 'doctor',     nombre: 'Doctor' },
  '131':          { id: 'emergencia', nombre: 'Emergencia' }
};

const contacto = mapaContactos[numero] || { id: 'desconocido', nombre };

return [{
  json: {
    tipo: 'llamada_entrante',
    datos: {
      numero,
      contacto_id:      contacto.id,
      nombre_mostrado:  contacto.nombre,
      timestamp:        new Date().toISOString()
    }
  }
}];
